package com.trademaster.ims.mobile.orders.controller;
import com.trademaster.ims.mobile.orders.dto.OrderDtos.*;import com.trademaster.ims.mobile.orders.service.MobileOrderService;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/mobile/v1/orders")public class MobileOrderController{private final MobileOrderService s;public MobileOrderController(MobileOrderService s){this.s=s;}private long a(Authentication x){return s.account(x);}@GetMapping public OrderPage list(Authentication x,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="10")int size,@RequestParam(required=false)String orderStatus,@RequestParam(required=false)String paymentStatus,@RequestParam(required=false)String dateFrom,@RequestParam(required=false)String dateTo,@RequestParam(required=false)String query,@RequestParam(defaultValue="newest")String sort){return s.list(a(x),page,size,orderStatus,paymentStatus,dateFrom,dateTo,query,sort);}@GetMapping("/{orderNumber}")public OrderDetail detail(Authentication x,@PathVariable String orderNumber){return s.detail(a(x),orderNumber);}@GetMapping("/{orderNumber}/timeline")public List<TimelineEntry>timeline(Authentication x,@PathVariable String orderNumber){return s.timeline(a(x),orderNumber);}@GetMapping("/{orderNumber}/cancellation-eligibility")public EligibilityResponse cancellation(Authentication x,@PathVariable String orderNumber){return s.cancellationEligibility(a(x),orderNumber);}@PostMapping("/{orderNumber}/cancellation-requests")@ResponseStatus(HttpStatus.CREATED)public CancellationRequestResponse cancel(Authentication x,@PathVariable String orderNumber,@Valid @RequestBody CancellationRequestDto q){return s.cancel(a(x),orderNumber,q);}@GetMapping("/{orderNumber}/cancellation-request")public ResponseEntity<CancellationRequestResponse>cancelRequest(Authentication x,@PathVariable String orderNumber){return s.existingCancellation(a(x),orderNumber).map(ResponseEntity::ok).orElseGet(()->ResponseEntity.notFound().build());}@GetMapping("/{orderNumber}/return-eligibility")public ReturnEligibilityResponse returnEligibility(Authentication x,@PathVariable String orderNumber){return s.returnEligibility(a(x),orderNumber);}@PostMapping("/{orderNumber}/return-requests")@ResponseStatus(HttpStatus.CREATED)public ReturnRequestResponse createReturn(Authentication x,@PathVariable String orderNumber,@Valid @RequestBody ReturnRequestDto q){return s.createReturn(a(x),orderNumber,q);}@GetMapping("/return-requests/{requestNumber}")public ReturnRequestResponse getReturn(Authentication x,@PathVariable String requestNumber){return s.getReturn(a(x),requestNumber);}@GetMapping("/{orderNumber}/document")public OrderDocumentResponse document(Authentication x,@PathVariable String orderNumber){return s.document(a(x),orderNumber);}}
